def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            for k in range(1, 4):
                score += (ratio ** k) / (k ** 2)
            score *= 20
        elif 1 < ratio <= 2:
            for j in range(1, 6):
                term = ((-1) ** j) * (ratio ** j) / j
                if j % 2 == 0:
                    term *= 1.2
                score += term
            score *= 10
        else:
            for m in range(1, 8):
                if m % 3 == 0:
                    score += (ratio ** m) / (m + 1)
                else:
                    score -= (ratio ** m) / (m + 1)
            if capacity < item * 1.5:
                score *= 2
            else:
                score *= 0.75
        if capacity % 2 == 0:
            score += np.log1p(capacity)
        else:
            score -= np.sqrt(capacity)
        priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 200
    return priorities
